def read_envelope(sock):
    env_size = struct.calcsize(ENV_FMT)
    env_bytes = b""
    while len(env_bytes) < env_size:
        chunk = sock.recv(env_size - len(env_bytes))
        if not chunk:
            break
        env_bytes += chunk
    if len(env_bytes) < env_size:
        env_bytes = env_bytes.ljust(env_size, b"\0")

