    out: list[str] = []
    for g in globs:
        for p in sorted((ROOT / base).glob(g)):
            rel = p.relative_to(ROOT).as_posix()
            for rx in patterns:
                if rx.search(rel):
                    out.append(rel)
                    break
    return out

